// Return current animated scale for a tap (1.0 when not hovered/settled)
fn hover_scale(id: u32) -> f64 {
    unsafe {
        VED_HOVER.iter()
            .find(|(hid, _, _, _)| *hid == id)
            .map(|(_, s, _, ms)| 1.0 + s.x * (ms - 1.0))
            .unwrap_or(1.0)
    }
}

