// ─── Tap action dispatch (generated from VED `on tap` bodies) ────────────────
fn dispatch(id: u32) {
    match id {
        0 => {
            st().website_page = 1;
        }
        1 => {
            st().website_page = 2;
        }
        2 => {
            st().website_page = 3;
        }
        3 => {
            st().website_page = 2;
        }
        4 => {
            st().website_page = 0;
        }
        5 => {
            st().website_page = 0;
        }
        6 => {
            st().website_page = 2;
        }
        7 => {
            st().website_page = 3;
        }
        8 => {
            st().website_page = 2;
        }
        9 => {
            st().website_page = 0;
        }
        10 => {
            st().website_page = 1;
        }
        11 => {
            st().website_page = 3;
        }
        12 => {
            st().website_learn_step = 1;
        }
        13 => {
            st().website_learn_step = 2;
        }
        14 => {
            st().website_learn_step = 0;
        }
        15 => {
            st().website_page = 3;
        }
        16 => {
            st().website_page = 0;
        }
        17 => {
            st().website_page = 1;
        }
        18 => {
            st().website_page = 2;
        }
        19 => {
            st().website_page = 3;
        }
        20 => {
            st().website_page = 3;
        }

        _ => {}
    }
}

// ─── Render dispatcher ───────────────────────────────────────────────────────
fn do_render() {
    unsafe { VED_TAPS.clear(); }
    unsafe { ved_clear(10, 10, 10); }
    render_website();
}

// ─── WASM exports (called from the VED HTML bootstrap) ───────────────────────

#[no_mangle]
pub extern "C" fn ved_init(w: f64, h: f64) {
    unsafe {
        VED_W = w; VED_H = h;
        VED_STATE = Some(AppState::new());
        VED_TAPS    = Vec::new();
        VED_HOVER   = Vec::new();
        VED_HOVERED = -1;
    }
    do_render();
}

#[no_mangle]
pub extern "C" fn ved_resize(w: f64, h: f64) {
    unsafe { VED_W = w; VED_H = h; }
    // Guard: do not render before ved_init has set up AppState
    if unsafe { VED_STATE.is_some() } {
        do_render();
    }
}

#[no_mangle]
pub extern "C" fn ved_tap(x: f64, y: f64) {
    let snap: Vec<(Rect, u32)> = unsafe { VED_TAPS.clone() };
    for (rect, id) in snap {
        if rect.hit(x, y) {
            dispatch(id);
            do_render();
            return;
        }
    }
}

#[no_mangle]
pub extern "C" fn ved_hover(x: f64, y: f64) {
    let taps: Vec<(Rect, u32)> = unsafe { VED_TAPS.clone() };
    let mut new_hovered: i32 = -1;
    for (rect, id) in &taps {
        if rect.hit(x, y) { new_hovered = *id as i32; break; }
    }
    let old_hovered = unsafe { VED_HOVERED };
    if new_hovered != old_hovered {
        unsafe { VED_HOVERED = new_hovered; }
        // Update spring targets: 1.0 for hovered, 0.0 for all others
        unsafe {
            for (hid, _, target, _) in VED_HOVER.iter_mut() {
                *target = if *hid as i32 == new_hovered { 1.0 } else { 0.0 };
            }
        }
        unsafe { ved_request_frame(); }
    }
}

#[no_mangle]
pub extern "C" fn ved_frame() {
    let dt = 1.0_f64 / 60.0;
    let mut animating = false;
    unsafe {
        for (_, spring, target, _) in VED_HOVER.iter_mut() {
            let settled = spring.tick(*target, dt);
            if !settled { animating = true; }
        }
    }
    do_render();
    if animating {
        unsafe { ved_request_frame(); }
    }
}
